arguments.argument:
if global.gamePaused=false
{
  if xVel>maxVel
    xVel=maxVel
  else if xVel<-maxVel
    xVel=-maxVel
  if xVel>0
    xVel-=0.05
  else if xVel<0
    xVel+=0.05
  yVel+=0.2
  if yVel>maxYvel
    yVel=maxYvel
  if isCollisionBottom(1)
    yVel=0
  //if isCollisionLeft(1)
  //  xVel=0
  //if isCollisionRight(1)
  //  xVel=0
  //if isCollisionSolid()
  //  y-=2
  if y>room_height+24
    instance_destroy()
}
